source:
Method -> {
  -> "GET"
  -> "POST"
  -> "DELETE"
}

Status -> u16 & >=100 & <600

Request -> {
  Method:method
  String:path
  String:body
}

Response -> {
  Status:status -> 200
  String:body -> ""
}

Log -> {
  String:message
}

userEndpoint -> {
  Request:req
  Log -< e {
    -> io.write{message -> e.message}!
  }
  -> req.method ? {
    "GET" -> Response{status -> 200 body -> "ok"}
    "POST" -> Response{status -> 201 body -> req.body}
    -> Response{status -> 405}
  }
}
